import{_ as a,o,c as t,ag as l}from"./chunks/framework.OsDJF_Ea.js";const u=JSON.parse('{"title":"Sampling Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"guides/sampling.md","filePath":"guides/sampling.md"}'),i={name:"guides/sampling.md"};function r(s,e,n,p,d,m){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="sampling-workflow" tabindex="-1">Sampling Workflow <a class="header-anchor" href="#sampling-workflow" aria-label="Permalink to &quot;Sampling Workflow&quot;">​</a></h1><p>The Smart Contact Mic can play audio samples from its SD card. There are several sample-based modules depending on your needs.</p><h2 id="preparing-samples" tabindex="-1">Preparing Samples <a class="header-anchor" href="#preparing-samples" aria-label="Permalink to &quot;Preparing Samples&quot;">​</a></h2><p>All samples should be:</p><ul><li><strong>WAV format</strong> (16-bit, stereo or mono)</li><li><strong>44.1 kHz sample rate</strong></li><li>Stored on a <strong>FAT32-formatted micro SD card</strong></li></ul><h2 id="sample-player" tabindex="-1">Sample Player <a class="header-anchor" href="#sample-player" aria-label="Permalink to &quot;Sample Player&quot;">​</a></h2><p>The <strong>Sample Player</strong> module plays a single WAV file with optional looping and polyphony.</p><ol><li>Add a Sample Player to your patch</li><li>Click the module title to open the <strong>Sample Editor</strong></li><li>Upload a WAV file from your computer -- it transfers to the SD card over USB</li><li>Connect a Button or MIDI gate to the <code>gate</code> input to trigger playback</li><li>Upload the patch</li></ol><h3 id="polyphonic-mode" tabindex="-1">Polyphonic Mode <a class="header-anchor" href="#polyphonic-mode" aria-label="Permalink to &quot;Polyphonic Mode&quot;">​</a></h3><p>Enable &quot;Polyphonic&quot; in the inspector for up to 6 overlapping voices. Each gate trigger starts a new voice without cutting the previous one.</p><h2 id="multi-sample-player" tabindex="-1">Multi Sample Player <a class="header-anchor" href="#multi-sample-player" aria-label="Permalink to &quot;Multi Sample Player&quot;">​</a></h2><p>The <strong>Multi Sample</strong> module holds 16 sample slots in 4 banks of 4. Ideal for drum kits, sound effects, or melodic sample sets.</p><ol><li>Add a Multi Sample module</li><li>Click the title to open the <strong>Multi Sample Editor</strong></li><li>Upload samples to individual slots (the waveform slicer lets you trim and crop)</li><li>Buttons 1-4 trigger the current bank&#39;s 4 slots</li><li>A pot selects which bank is active</li></ol><p>Samples are stored in timestamped folders on the SD card (e.g., <code>ms_20260402_1430/</code>).</p><h2 id="audio-slicer" tabindex="-1">Audio Slicer <a class="header-anchor" href="#audio-slicer" aria-label="Permalink to &quot;Audio Slicer&quot;">​</a></h2><p>The <strong>Audio Slicer</strong> records live audio into PSRAM, automatically divides it into slices, and triggers them via MIDI. Great for beat-slicing and live resampling.</p><h2 id="importing-recordings" tabindex="-1">Importing Recordings <a class="header-anchor" href="#importing-recordings" aria-label="Permalink to &quot;Importing Recordings&quot;">​</a></h2><p>If you&#39;ve used the Audio Recorder module to capture audio to SD, you can import those recordings into the Multi Sample Editor using the &quot;Import from Device&quot; button.</p>',18)])])}const h=a(i,[["render",r]]);export{u as __pageData,h as default};
